INSERT INTO audit_record (
    audit_id, application_id, auditor_id, audit_result, audit_opinion, audit_time
) VALUES (
             #{auditId}, #{applicationId}, #{auditorId}, #{auditResult}, #{auditOpinion}, #{auditTime}
         )

mapper.select:
SELECT ar.audit_id AS auditId, ar.application_id AS applicationId, ar.auditor_id AS auditorId, ar.audit_result AS auditResult, ar.audit_opinion AS auditOpinion, ar.audit_time AS auditTime, la.apply_amount AS applyAmount, la.apply_term AS applyTerm, lp.product_name AS productName, la.user_id AS userId, su.real_name AS userName FROM audit_record ar LEFT JOIN loan_application la ON ar.application_id = la.application_id LEFT JOIN loan_product lp ON la.product_id = lp.product_id LEFT JOIN sys_user su ON la.user_id = su.user_id WHERE ar.auditor_id = #{auditorId}
AND DATE(ar.audit_time) >= #{startDate}
AND DATE(ar.audit_time) <= #{endDate}
ORDER BY ar.audit_time DESC LIMIT #{offset}, #{limit}
